var e=[{id:`L2_1`,type:`dialog`,speaker:`SORIM_REBBIT_NULL_NULL`,text:{KOREA:`여기는 코드네임 <color=#ffd34c>심판의 방아쇠</color>.`,JPN:`こちらコードネーム<color=#ffd34c>審判の引き金</color>。`,ENG:`This is code name <color=#ffd34c>Trigger of Judgment</color>.`,TWN:`我是代碼名<color=#ffd34c>審判的扳機</color>。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`SORIM_REBBIT_NULL_NULL`,text:{KOREA:`현재 좌표 찰리-식스, 브라보-나인. 목표물을 발견했다.`,JPN:`現在の座標チャーリー・シックス、ブラボー・ナイン。ターゲットを発見した。`,ENG:`The current coordinates are as stated, Charlie, Six, Bravo, Nine. I've spotted the target.`,TWN:`當前座標是查理-六，布拉伯-九，發現目標。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`SORIM_REBBIT_NULL_NULL`,text:{KOREA:`교전 승인을 요청한다. <color=#ffd34c>캡틴 래빗</color>.`,JPN:`交戦承認を要請する。<color=#ffd34c>キャプテン・ラビット</color>。`,ENG:`I'm requesting permission to engage, <color=#ffd34c>Captain Rabbit</color>.`,TWN:`請求批準交戰，<color=#ffd34c>兔子隊長</color>。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`HARIM_REBBIT_NULL_NULL`,text:{KOREA:`여기는 캡틴 래빗.`,JPN:`こちらキャプテン・ラビット。`,ENG:`This is Captain Rabbit.`,TWN:`我是兔子隊長。`},stage:{bg:`BLACK`,slots:{L:null,C:{char_id:`HARIM_REBBIT_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`HARIM_REBBIT_NULL_NULL`,text:{KOREA:`교전을 승인한다. 자비 없이 목표물을 제압하도록.`,JPN:`交戦を承認する。容赦なくターゲットを制圧すること。`,ENG:`Permission granted. Take out the target. Show no mercy.`,TWN:`批準交戰，毫不留情地攻擊目標吧。`},stage:{bg:`BLACK`,slots:{L:null,C:{char_id:`HARIM_REBBIT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`SORIM_REBBIT_NULL_NULL`,text:{KOREA:`롸져.`,JPN:`ラジャー。`,ENG:`Roger.`,TWN:`收到。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`SORIM_REBBIT_NULL_NULL`,text:{KOREA:`들었나? 스미스 병장?`,JPN:`聞いたかな？　スミス兵長？`,ENG:`Did you hear that, Sergeant Smith?`,TWN:`聽見了嗎？史密斯兵長？`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`SORIM_REBBIT_NULL_NULL`,text:{KOREA:`오랜만에 돌아온 전장의 공기가 상쾌하군.`,JPN:`久しぶりに帰ってきた戦場の空気は爽やかでいいぞ。`,ENG:`I missed the crisp air of the battlefield.`,TWN:`好久沒上戰場了，戰場上的空氣可真新鮮啊。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`SMITH_TOY_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:`SORIM_REBBIT_NULL_NULL`,text:{KOREA:`그래. 방심은 금물이지. 잘 알고 있다.`,JPN:`そうだな、油断は禁物だ。わかっている。`,ENG:`Right. I shouldn't let my guard down. I'm aware of that.`,TWN:`是啊，切忌掉以輕心。我很清楚。`},stage:{bg:`BLACK`,slots:{L:null,C:{char_id:`SORIM_REBBIT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`SORIM_REBBIT_NULL_NULL`,text:{KOREA:`......지금이닷!`,JPN:`……今だっ！`,ENG:`... Now!`,TWN:`……就是現在！`},stage:{bg:`BLACK`,slots:{L:null,C:{char_id:`SORIM_REBBIT_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`HANDGUN_ACADEMY_NULL_NULL`,text:{KOREA:`아얏!`,JPN:`いたっ！`,ENG:`Ouch!`,TWN:`啊呀！`},stage:{bg:`PROLOGUE_02`,slots:{L:null,C:{char_id:`HANDGUN_ACADEMY_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`HANDGUN_ACADEMY_NULL_NULL`,text:{KOREA:`누, 누구야! 비비탄을 사람한테 쏴대는 게!`,JPN:`だ、誰！？　人に向かってBB弾を撃ってるのは！？`,ENG:`W-who's shooting a BB gun at me?`,TWN:`誰，誰！是誰拿BB彈射人的！`},stage:{bg:`PROLOGUE_02`,slots:{L:null,C:{char_id:`HANDGUN_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`SORIM_REBBIT_NULL_NULL`,text:{KOREA:`미안하군. 브라우니 교관.`,JPN:`悪かったな、ブラウニー教官。`,ENG:`I'm sorry, Instructor Brownie.`,TWN:`對不起，布朗尼教官。`},stage:{bg:`PROLOGUE_02`,slots:{L:null,C:{char_id:`SORIM_REBBIT_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`SORIM_REBBIT_NULL_NULL`,text:{KOREA:`하지만 캡틴 래빗의 명령이 떨어진 이상, 본관은 차가운 전쟁기계일 뿐이다.`,JPN:`しかし、キャプテン・ラビットの命令が下された以上、
本官は血も涙もない兵器に過ぎない。`,ENG:`But Captain Rabbit gave me an order. Now I'm a merciless war machine.`,TWN:`不過既然兔子隊長已經下命令了，本官就只是一台冰冷的戰爭機械而已。`},stage:{bg:`PROLOGUE_02`,slots:{L:null,C:{char_id:`SORIM_REBBIT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`HANDGUN_ACADEMY_NULL_NULL`,text:{KOREA:`소, 소림이잖아?`,JPN:`ミ、ミズキさん？`,ENG:`S-Sorim?`,TWN:`夏，夏琳？`},stage:{bg:`PROLOGUE_02`,slots:{L:null,C:{char_id:`HANDGUN_ACADEMY_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`HANDGUN_ACADEMY_NULL_NULL`,text:{KOREA:`여긴 내 전용 탐사선인데? 어떻게 들어 온 거야?`,JPN:`ここは私の専用探査機なのに？　どうやって入ってきたの？`,ENG:`But this is my exploration probe! How did you get in?`,TWN:`這是我的專用勘探船，你是怎麼進來的？`},stage:{bg:`PROLOGUE_02`,slots:{L:null,C:{char_id:`HANDGUN_ACADEMY_NULL_NULL`,face:`UNIT_HATE`},R:null}}}];export{e as default};